import React from 'react';
import { motion } from 'framer-motion';

const Services: React.FC = () => {
  const services = [
    {
      title: "3D Rendering & Visualization",
      description: "Bringing your vision to life with stunning 3D renderings and immersive visualizations",
      icon: "🏗️"
    },
    {
      title: "Interior Design Consultation",
      description: "Expert guidance and personalized design solutions tailored to your space and style",
      icon: "💡"
    },
    {
      title: "Residential & Commercial Interiors",
      description: "Complete interior design solutions for both residential and commercial spaces",
      icon: "🏢"
    },
    {
      title: "Furniture Layouts & Detailing",
      description: "Optimized furniture arrangements with detailed specifications and layouts",
      icon: "🪑"
    },
    {
      title: "Working Drawings",
      description: "Professional technical drawings and documentation for implementation",
      icon: "📐"
    },
    {
      title: "Concept & Moodboard Development",
      description: "Creative concept development and moodboards to establish your design direction",
      icon: "🎨"
    },
    {
      title: "Renovation & Makeover Design",
      description: "Transformative renovation designs and complete space makeovers",
      icon: "🔨"
    }
  ];

  return (
    <section id="services" className="py-20 bg-gradient-to-b from-black to-gray-900">
      <div className="container mx-auto px-6">
        <motion.div
          className="text-center mb-16"
          initial={{ opacity: 0, y: 50 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          viewport={{ once: true }}
        >
          <h2 className="text-4xl md:text-5xl font-bold mb-4">
            <span className="gradient-text">Our Services</span>
          </h2>
          <p className="text-gray-400 text-lg max-w-2xl mx-auto">
            Comprehensive interior design solutions from concept to completion
          </p>
        </motion.div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {services.map((service, index) => (
            <motion.div
              key={index}
              className="glass-effect rounded-2xl p-8 card-hover group cursor-pointer"
              initial={{ opacity: 0, y: 50 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, delay: index * 0.1 }}
              viewport={{ once: true }}
              whileHover={{ 
                scale: 1.05,
                boxShadow: "0 20px 40px rgba(139, 69, 19, 0.3)"
              }}
            >
              <motion.div
                className="text-4xl mb-4"
                whileHover={{ rotate: [0, -10, 10, 0] }}
                transition={{ duration: 0.5 }}
              >
                {service.icon}
              </motion.div>
              
              <h3 className="text-xl font-semibold mb-3 text-white group-hover:text-amber-400 transition-colors duration-300">
                {service.title}
              </h3>
              
              <p className="text-gray-400 leading-relaxed">
                {service.description}
              </p>

              <motion.div
                className="mt-6 h-0.5 bg-gradient-to-r from-transparent via-amber-500 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300"
                initial={{ width: 0 }}
                whileHover={{ width: "100%" }}
                transition={{ duration: 0.3 }}
              />
            </motion.div>
          ))}
        </div>

        <motion.div
          className="text-center mt-16"
          initial={{ opacity: 0 }}
          whileInView={{ opacity: 1 }}
          transition={{ duration: 0.8, delay: 0.5 }}
          viewport={{ once: true }}
        >
          <motion.a
            href="#contact"
            className="inline-block px-8 py-4 bg-gradient-to-r from-amber-600 to-orange-600 text-white rounded-full font-semibold hover:shadow-lg hover:shadow-amber-500/25 transition-all duration-300"
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            Discuss Your Project
          </motion.a>
        </motion.div>
      </div>
    </section>
  );
};

export default Services;
